#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        if (K < 0 || K > N*(N-1)/2 + (N-1)) {
            printf("-1\n");
        } else {
            int arr[N];
            for (int i = 0; i < N; i++) {
                arr[i] = i+1;
            }
            // Try to construct a permutation that satisfies the condition
            int sum = 0;
            for (int i = 0; i < N-1; i++) {
                sum += arr[i] > arr[i+1] ? arr[i] : arr[i+1];
            }
            if (sum == K) {
                for (int i = 0; i < N; i++) {
                    printf("%d ", arr[i]);
                }
                printf("\n");
            } else {
                // If the sum is less than K, try to increase it by swapping elements
                for (int i = 0; i < N-1; i++) {
                    if (sum < K && arr[i] < arr[i+1]) {
                        int temp = arr[i];
                        arr[i] = arr[i+1];
                        arr[i+1] = temp;
                        sum = 0;
                        for (int j = 0; j < N-1; j++) {
                            sum += arr[j] > arr[j+1] ? arr[j] : arr[j+1];
                        }
                        if (sum == K) {
                            for (int j = 0; j < N; j++) {
                                printf("%d ", arr[j]);
                            }
                            printf("\n");
                            break;
                        }
                    }
                }
                if (sum != K) {
                    printf("-1\n");
                }
            }
        }
    }
    return 0;
}

