                // If the sum is less than K, try to increase it by swapping elements
                for (int i = 0; i < N-1; i++) {
                    if (sum < K && arr[i] < arr[i+1]) {
                        swap(arr[i], arr[i+1]);
                        sum = 0;
                        for (int j = 0; j < N-1; j++) {
                            sum += max(arr[j], arr[j+1]);
                        }
                        if (sum == K) {
                            for (int j = 0; j < N; j++) {
                                cout << arr[j] << " ";
                            }
                            cout << endl;
                            break;
                        }
                    }
                }
                if (sum != K) {
                    cout << -1 << endl;
                }
            }
        }
    }
