                    sum += Math.max(arr[i], arr[i+1]);
                }
                if (sum == K) {
                    for (int i = 0; i < N; i++) {
                        System.out.print(arr[i] + " ");
                    }
                    System.out.println();
                } else {
                    // If the sum is less than K, try to increase it by swapping elements
                    for (int i = 0; i < N-1; i++) {
                        if (sum < K && arr[i] < arr[i+1]) {
                            int temp = arr[i];
                            arr[i] = arr[i+1];
                            arr[i+1] = temp;
                            sum = 0;
                            for (int j = 0; j < N-1; j++) {
                                sum += Math.max(arr[j], arr[j+1]);
                            }
